#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int *P = (int*)malloc(N*sizeof(int));
        for(int i=0;i<N;i++) scanf("%d", &P[i]);
        // find blocks
        int ops = 0;
        int *L = (int*)malloc(N*sizeof(int));
        int *R = (int*)malloc(N*sizeof(int));
        for(int i=0;i<N;){
            if(P[i]==i+1){ i++; continue; }
            int l=i;
            while(i<N && P[i]!=i+1) i++;
            int r=i-1;
            L[ops]=l; R[ops]=r; ops++;
        }
        printf("%d\n", ops);
        for(int k=0;k<ops;k++){
            int l=L[k], r=R[k];
            // apply operation
            for(int i=l;i<=r;i++) P[i]=i+1;
            printf("%d %d\n", l+1, r+1);
            for(int i=0;i<N;i++){
                if(i) printf(" ");
                printf("%d", P[i]);
            }
            printf("\n");
        }
        free(P); free(L); free(R);
    }
    return 0;
}

