import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int[] p = new int[N];
            for (int i = 0; i < N; i++) p[i] = fs.nextInt();
            List<int[]> blocks = new ArrayList<>();
            for (int i = 0; i < N; ) {
                if (p[i] == i + 1) { i++; continue; }
                int l = i;
                while (i < N && p[i] != i + 1) i++;
                int r = i - 1;
                blocks.add(new int[]{l, r});
            }
            out.append(blocks.size()).append('\n');
            for (int[] seg : blocks) {
                int l = seg[0], r = seg[1];
                for (int i = l; i <= r; i++) p[i] = i + 1;
                out.append(l + 1).append(' ').append(r + 1).append('\n');
                for (int i = 0; i < N; i++) {
                    if (i > 0) out.append(' ');
                    out.append(p[i]);
                }
                out.append('\n');
            }
        }
        System.out.print(out.toString());
    }

    // fast scanner
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

