#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        p = [int(next(it)) for _ in range(N)]
        blocks = []
        i = 0
        while i < N:
            if p[i] == i + 1:
                i += 1
                continue
            l = i
            while i < N and p[i] != i + 1:
                i += 1
            r = i - 1
            blocks.append((l, r))
        out_lines.append(str(len(blocks)))
        for l, r in blocks:
            for idx in range(l, r + 1):
                p[idx] = idx + 1
            out_lines.append(f"{l+1} {r+1}")
            out_lines.append(' '.join(map(str, p)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

